import type { CareerQuestion } from "./rrt-questions";

export const addictionsCounsellorQuestionsBatch5: CareerQuestion[] = [
  { id: "cac-751", stem: "Alcohol primarily exerts its depressant effects by enhancing the activity of which neurotransmitter system?", options: ["GABA (gamma-aminobutyric acid)", "Dopamine", "Serotonin", "Acetylcholine"], correctIndex: 0, rationale: "Alcohol potentiates GABA-A receptor activity, increasing chloride ion influx and neuronal inhibition. This accounts for its sedative, anxiolytic, and motor-impairing effects.", difficulty: 2, category: "Pharmacology of Substances", topic: "Alcohol Mechanisms" },
  { id: "cac-752", stem: "The primary mechanism by which opioids produce analgesia involves binding to which receptor type?", options: ["Mu (μ) opioid receptors in the central nervous system", "Nicotinic acetylcholine receptors", "NMDA glutamate receptors", "Alpha-2 adrenergic receptors"], correctIndex: 0, rationale: "Mu opioid receptors in the brain and spinal cord mediate analgesia, euphoria, respiratory depression, and physical dependence. Delta and kappa receptors also contribute but mu is primary.", difficulty: 1, category: "Pharmacology of Substances", topic: "Opioid Mechanisms" },
  { id: "cac-753", stem: "Cocaine produces its stimulant effects primarily by:", options: ["Blocking the reuptake of dopamine, norepinephrine, and serotonin at the synaptic cleft", "Stimulating GABA release in the prefrontal cortex", "Directly activating opioid receptors", "Inhibiting monoamine oxidase enzymes"], correctIndex: 0, rationale: "Cocaine blocks monoamine transporters (DAT, NET, SERT), preventing reuptake and increasing synaptic concentrations. The dopamine reuptake blockade in the nucleus accumbens is most responsible for its reinforcing effects.", difficulty: 2, category: "Pharmacology of Substances", topic: "Stimulant Mechanisms" },
  { id: "cac-754", stem: "THC (delta-9-tetrahydrocannabinol) produces its psychoactive effects by activating:", options: ["CB1 cannabinoid receptors in the brain", "Opioid receptors in the brainstem", "GABA-B receptors in the cerebellum", "5-HT2A serotonin receptors in the cortex"], correctIndex: 0, rationale: "THC is a partial agonist at CB1 receptors, which are densely distributed in the hippocampus, cerebellum, basal ganglia, and cortex. CB1 activation accounts for euphoria, memory impairment, altered time perception, and appetite stimulation.", difficulty: 2, category: "Pharmacology of Substances", topic: "Cannabis Pharmacology" },
  { id: "cac-755", stem: "LSD (lysergic acid diethylamide) produces hallucinogenic effects primarily through:", options: ["Agonism at 5-HT2A serotonin receptors in the cerebral cortex", "Blockade of dopamine D2 receptors", "Enhancement of GABA transmission", "Inhibition of acetylcholinesterase"], correctIndex: 0, rationale: "LSD is a potent 5-HT2A receptor agonist. Activation of these receptors in layer V cortical pyramidal neurons disrupts thalamocortical gating, producing visual hallucinations, synesthesia, and altered cognition.", difficulty: 3, category: "Pharmacology of Substances", topic: "Hallucinogen Mechanisms" },
  { id: "cac-756", stem: "Benzodiazepines enhance the effect of GABA by:", options: ["Increasing the frequency of chloride channel opening at the GABA-A receptor", "Increasing the duration of chloride channel opening", "Directly opening chloride channels without GABA", "Stimulating GABA synthesis in presynaptic neurons"], correctIndex: 0, rationale: "Benzodiazepines are positive allosteric modulators at GABA-A receptors that increase the frequency of chloride channel opening when GABA is present. Barbiturates, by contrast, increase the duration of opening.", difficulty: 3, category: "Pharmacology of Substances", topic: "Sedative Mechanisms" },
  { id: "cac-757", stem: "Alcohol withdrawal seizures most commonly occur within what time frame after cessation of heavy drinking?", options: ["12-48 hours", "1-4 hours", "5-7 days", "2-3 weeks"], correctIndex: 0, rationale: "Alcohol withdrawal seizures typically occur 12-48 hours after the last drink, often as generalized tonic-clonic seizures. They result from unopposed glutamate excitatory activity after chronic GABA enhancement is removed.", difficulty: 2, category: "Pharmacology of Substances", topic: "Alcohol Withdrawal" },
  { id: "cac-758", stem: "The opioid withdrawal timeline for short-acting opioids (heroin) typically begins:", options: ["6-12 hours after the last dose, peaking at 36-72 hours", "Immediately upon discontinuation", "3-5 days after the last dose", "2 weeks after the last dose"], correctIndex: 0, rationale: "Short-acting opioid withdrawal begins 6-12 hours after last use, peaks at 36-72 hours, and largely resolves by 5-7 days. Symptoms include lacrimation, rhinorrhea, myalgia, diarrhea, piloerection, and intense craving.", difficulty: 2, category: "Pharmacology of Substances", topic: "Opioid Withdrawal" },
  { id: "cac-759", stem: "Methamphetamine differs from cocaine in its duration of action because:", options: ["Methamphetamine has a much longer half-life (10-12 hours vs. 1 hour) and resists enzymatic breakdown", "Methamphetamine is water-soluble while cocaine is lipid-soluble", "Cocaine crosses the blood-brain barrier more slowly", "Methamphetamine is metabolized faster by plasma cholinesterases"], correctIndex: 0, rationale: "Methamphetamine's longer half-life (10-12 hours vs. cocaine's ~1 hour) is due to resistance to monoamine oxidase metabolism. It also promotes dopamine release rather than just blocking reuptake, producing more prolonged effects.", difficulty: 3, category: "Pharmacology of Substances", topic: "Stimulant Mechanisms" },
  { id: "cac-760", stem: "Cannabis use during adolescence is particularly concerning because:", options: ["The endocannabinoid system plays a critical role in neurodevelopment and THC exposure may permanently alter brain maturation", "Cannabis has no effects on the developing brain", "Adolescents metabolize THC faster, reducing any potential harm", "Cannabis only affects motor coordination in young users"], correctIndex: 0, rationale: "The endocannabinoid system guides synaptic pruning and white matter development during adolescence. Chronic THC exposure during this period is associated with lasting deficits in memory, executive function, and increased psychosis risk.", difficulty: 3, category: "Pharmacology of Substances", topic: "Cannabis Effects" },
  { id: "cac-761", stem: "Psilocybin, the active compound in 'magic mushrooms,' is pharmacologically classified as a:", options: ["Tryptamine hallucinogen and 5-HT2A receptor agonist", "Dissociative anesthetic", "Stimulant and dopamine agonist", "Sedative-hypnotic"], correctIndex: 0, rationale: "Psilocybin is dephosphorylated to psilocin, a tryptamine that activates 5-HT2A receptors. Effects include visual distortions, mystical experiences, and altered cognition lasting 4-6 hours. Recent research shows therapeutic potential for depression and addiction.", difficulty: 3, category: "Pharmacology of Substances", topic: "Hallucinogen Mechanisms" },
  { id: "cac-762", stem: "GHB (gamma-hydroxybutyrate) withdrawal can be life-threatening because it may cause:", options: ["Autonomic instability, delirium, and seizures similar to alcohol/benzodiazepine withdrawal", "Only mild insomnia and irritability", "Respiratory depression identical to opioid overdose", "Permanent peripheral neuropathy"], correctIndex: 0, rationale: "GHB acts on GABA-B and GHB receptors. Withdrawal from chronic use produces a severe syndrome resembling alcohol/benzodiazepine withdrawal with potential for delirium, seizures, rhabdomyolysis, and death. Onset is typically 1-6 hours after last dose.", difficulty: 4, category: "Pharmacology of Substances", topic: "Sedative Withdrawal" },
  { id: "cac-763", stem: "The primary neurotransmitter implicated in the rewarding effects of most substances of abuse is:", options: ["Dopamine in the mesolimbic pathway", "Serotonin in the raphe nuclei", "Norepinephrine in the locus coeruleus", "Acetylcholine in the basal forebrain"], correctIndex: 0, rationale: "The mesolimbic dopamine pathway (ventral tegmental area to nucleus accumbens) is the common reward circuit activated by virtually all addictive substances, either directly or indirectly increasing dopamine release.", difficulty: 1, category: "Pharmacology of Substances", topic: "Neurobiology of Addiction" },
  { id: "cac-764", stem: "Combining opioids with benzodiazepines significantly increases overdose risk primarily because:", options: ["Both cause respiratory depression through different mechanisms, creating synergistic CNS depression", "Benzodiazepines accelerate opioid metabolism", "Opioids block the sedative effects of benzodiazepines causing compensatory overdosing", "The combination produces stimulant effects leading to cardiac arrest"], correctIndex: 0, rationale: "Opioids depress respiration via brainstem mu receptors while benzodiazepines reduce respiratory drive through GABA-A enhancement. Together they produce synergistic respiratory depression, accounting for a large proportion of overdose deaths.", difficulty: 2, category: "Pharmacology of Substances", topic: "Drug Interactions" },
  { id: "cac-765", stem: "Kindling in the context of alcohol withdrawal refers to:", options: ["Progressive worsening of withdrawal symptoms with each successive episode of detoxification", "The initial onset of alcohol dependence", "A technique used in alcohol treatment", "Gradual improvement in withdrawal symptoms over time"], correctIndex: 0, rationale: "Kindling describes neuroadaptation where repeated alcohol withdrawal episodes cause progressively more severe symptoms, lower seizure thresholds, and increased risk of delirium tremens. This has implications for repeated detoxification without sustained treatment.", difficulty: 4, category: "Pharmacology of Substances", topic: "Alcohol Withdrawal" },
  { id: "cac-766", stem: "Kratom (Mitragyna speciosa) produces its effects primarily by:", options: ["Acting as a partial agonist at mu-opioid receptors and an antagonist at delta-opioid receptors", "Blocking serotonin reuptake exclusively", "Enhancing GABA-A receptor activity like benzodiazepines", "Inhibiting dopamine synthesis"], correctIndex: 0, rationale: "Kratom's active alkaloids (mitragynine, 7-hydroxymitragynine) act at opioid receptors with partial agonist properties. At low doses it produces stimulant effects; at higher doses, opioid-like analgesia and sedation. Withdrawal mimics opioid withdrawal.", difficulty: 4, category: "Pharmacology of Substances", topic: "Emerging Substances" },
  { id: "cac-767", stem: "The pharmacological rationale for using long-acting benzodiazepines (chlordiazepoxide, diazepam) in alcohol withdrawal is:", options: ["They cross-react with GABA-A receptors to prevent withdrawal seizures and provide smooth, self-tapering coverage", "They enhance glutamate activity to stabilize neurons", "They block alcohol metabolism to prevent relapse", "They directly replenish depleted GABA stores"], correctIndex: 0, rationale: "Long-acting benzodiazepines substitute for alcohol's GABA-A receptor effects, preventing hyperexcitability and seizures. Their long half-lives provide smoother withdrawal coverage and allow for symptom-triggered dosing protocols.", difficulty: 3, category: "Pharmacology of Substances", topic: "Alcohol Withdrawal" },
  { id: "cac-768", stem: "MDMA (ecstasy/molly) produces its characteristic empathogenic effects primarily by:", options: ["Causing massive release of serotonin, and to a lesser extent dopamine and norepinephrine", "Blocking GABA receptors in the amygdala", "Activating kappa-opioid receptors", "Inhibiting glutamate release in the hippocampus"], correctIndex: 0, rationale: "MDMA enters neurons via monoamine transporters and reverses their function, causing massive serotonin release. This produces feelings of emotional closeness, empathy, and euphoria. Neurotoxicity to serotonergic neurons is a concern with repeated use.", difficulty: 3, category: "Pharmacology of Substances", topic: "Stimulant Mechanisms" },
  { id: "cac-769", stem: "A client on methadone maintenance presents with prolonged QTc interval on ECG. This is clinically significant because:", options: ["Methadone can prolong QTc interval, increasing risk of torsades de pointes and sudden cardiac death", "QTc prolongation indicates liver failure from methadone", "This finding is unrelated to methadone and can be ignored", "QTc prolongation means the methadone dose is too low"], correctIndex: 0, rationale: "Methadone blocks hERG potassium channels, prolonging cardiac repolarization (QTc). QTc >500ms significantly increases risk of torsades de pointes, a life-threatening ventricular arrhythmia. Baseline and follow-up ECGs are recommended.", difficulty: 4, category: "Pharmacology of Substances", topic: "Opioid Side Effects" },
  { id: "cac-770", stem: "Synthetic cannabinoids (K2, Spice) are more dangerous than natural cannabis because:", options: ["They are full agonists at CB1 receptors (vs. THC's partial agonism) and have unpredictable potency", "They contain lower concentrations of psychoactive chemicals", "They have shorter duration of action with no adverse effects", "They are chemically identical to THC"], correctIndex: 0, rationale: "Synthetic cannabinoids are full CB1 agonists with potencies 10-800x greater than THC. Variable compositions cause unpredictable effects including seizures, psychosis, rhabdomyolysis, acute kidney injury, and death.", difficulty: 3, category: "Pharmacology of Substances", topic: "Cannabis Pharmacology" },
  { id: "cac-771", stem: "Alcohol inhibits glutamate activity primarily by blocking which receptor?", options: ["NMDA (N-methyl-D-aspartate) receptor", "AMPA receptor exclusively", "Kainate receptor", "Metabotropic glutamate receptor 5"], correctIndex: 0, rationale: "Alcohol is an NMDA receptor antagonist, reducing excitatory glutamate transmission. Chronic alcohol use causes compensatory NMDA receptor upregulation, which upon cessation produces the glutamatergic hyperexcitability underlying withdrawal symptoms.", difficulty: 3, category: "Pharmacology of Substances", topic: "Alcohol Mechanisms" },
  { id: "cac-772", stem: "Neonatal abstinence syndrome (NAS) from maternal opioid use typically presents within:", options: ["24-72 hours after birth with irritability, high-pitched cry, tremors, poor feeding, and diarrhea", "Immediately at delivery with respiratory depression", "2-4 weeks after birth", "Only in premature infants"], correctIndex: 0, rationale: "NAS onset depends on the specific opioid (shorter-acting = earlier onset). Symptoms include CNS hyperirritability, GI dysfunction, autonomic signs, and poor feeding. Methadone-exposed neonates may present later (48-72 hours) due to its long half-life.", difficulty: 2, category: "Pharmacology of Substances", topic: "Opioid Effects" },
  { id: "cac-773", stem: "Cocaine-induced chest pain should be treated differently from typical cardiac ischemia because:", options: ["Beta-blockers are contraindicated as they can worsen coronary vasospasm from unopposed alpha-adrenergic stimulation", "Aspirin is contraindicated in cocaine users", "Nitrates are never used in cocaine-related chest pain", "Standard STEMI protocols apply without modification"], correctIndex: 0, rationale: "Beta-blockers are avoided in cocaine-related chest pain because blocking beta-2 vasodilation leaves alpha-1 vasoconstriction unopposed, worsening coronary vasospasm and hypertension. Benzodiazepines and nitrates are preferred initial treatments.", difficulty: 5, category: "Pharmacology of Substances", topic: "Stimulant Effects" },
  { id: "cac-774", stem: "The ceiling effect of buprenorphine refers to:", options: ["A plateau in respiratory depression and euphoria at higher doses, improving its safety profile", "The maximum number of patients a prescriber can treat", "A limit on how long the medication can be prescribed", "The point at which tolerance develops"], correctIndex: 0, rationale: "As a partial mu-agonist, buprenorphine's effects plateau at moderate doses — increasing the dose further does not proportionally increase respiratory depression or euphoria. This ceiling effect makes fatal overdose from buprenorphine alone rare.", difficulty: 2, category: "Pharmacology of Substances", topic: "Opioid Mechanisms" },
  { id: "cac-775", stem: "Phencyclidine (PCP) intoxication is characterized by:", options: ["Nystagmus, dissociation, agitation, analgesia, hypertension, and potential for violent behavior", "Pinpoint pupils and respiratory depression", "Relaxation and sedation without agitation", "Purely visual hallucinations without behavioral changes"], correctIndex: 0, rationale: "PCP is an NMDA receptor antagonist and dissociative anesthetic. Intoxication produces horizontal and vertical nystagmus (pathognomonic), analgesia, agitation, psychosis, and superhuman-strength perception. It also has dopaminergic and sigma receptor activity.", difficulty: 3, category: "Pharmacology of Substances", topic: "Hallucinogen Effects" },
  { id: "cac-776", stem: "Chronic heavy alcohol use leads to hepatic enzyme induction, which clinically means:", options: ["Cross-tolerance to other CNS depressants and faster metabolism of medications processed by the liver", "Decreased tolerance to all medications", "Improved liver function over time", "Reduced alcohol metabolism requiring lower doses"], correctIndex: 0, rationale: "Chronic alcohol induces cytochrome P450 enzymes (especially CYP2E1), increasing metabolism of alcohol and other drugs. This contributes to cross-tolerance with benzodiazepines and barbiturates and can alter dosing of many medications.", difficulty: 3, category: "Pharmacology of Substances", topic: "Drug Interactions" },
  { id: "cac-777", stem: "Stimulant withdrawal (cocaine, methamphetamine) is characterized primarily by:", options: ["Fatigue, hypersomnia, increased appetite, dysphoria, and psychomotor retardation ('crash')", "Seizures and autonomic instability", "Respiratory depression requiring intubation", "Visual hallucinations and delirium tremens"], correctIndex: 0, rationale: "Stimulant withdrawal produces a 'crash' with exhaustion, hypersomnia, hyperphagia, and depression due to dopamine depletion. While not typically medically dangerous (unlike alcohol/benzodiazepine withdrawal), severe depression with suicidal ideation is a risk.", difficulty: 1, category: "Pharmacology of Substances", topic: "Stimulant Withdrawal" },
  { id: "cac-778", stem: "Gabapentin and pregabalin are increasingly being used in substance use treatment but carry abuse potential because:", options: ["They produce euphoria, anxiolysis, and dissociation-like effects at supratherapeutic doses, particularly in opioid users", "They are pure opioid agonists", "They have the same mechanism as benzodiazepines", "They cause stimulant-like effects identical to cocaine"], correctIndex: 0, rationale: "Gabapentinoids bind alpha-2-delta calcium channel subunits, but at high doses produce euphoria and potentiate opioid effects. They are increasingly diverted in the addiction population and some states now schedule them as controlled substances.", difficulty: 4, category: "Pharmacology of Substances", topic: "Drug Interactions" },
  { id: "cac-779", stem: "The alcohol flush reaction seen in many East Asian individuals is caused by:", options: ["A genetic variant of aldehyde dehydrogenase (ALDH2*2) that impairs acetaldehyde metabolism", "Increased alcohol dehydrogenase activity", "Allergic reaction to congeners in alcoholic beverages", "Histamine intolerance unrelated to alcohol metabolism"], correctIndex: 0, rationale: "The ALDH2*2 allele (common in ~30-40% of East Asians) encodes a dysfunctional aldehyde dehydrogenase enzyme, causing acetaldehyde accumulation after drinking. This produces facial flushing, tachycardia, and nausea — a natural disulfiram-like reaction that is protective against alcohol use disorder.", difficulty: 3, category: "Pharmacology of Substances", topic: "Alcohol Mechanisms" },
  { id: "cac-780", stem: "Naltrexone for opioid use disorder should not be initiated until the patient has been opioid-free for at least:", options: ["7-10 days to avoid precipitating acute withdrawal", "24 hours", "1 hour after last opioid use", "30 days"], correctIndex: 0, rationale: "Naltrexone is a full opioid antagonist that will displace any remaining opioids from receptors, precipitating severe withdrawal. A minimum 7-10 day opioid-free period (longer for methadone) is required. Urine drug screening and naloxone challenge may be used to confirm clearance.", difficulty: 2, category: "Pharmacology of Substances", topic: "Opioid Mechanisms" },
  { id: "cac-781", stem: "Inhalant abuse (volatile solvents like toluene) produces intoxication through:", options: ["Enhancing GABA activity and inhibiting glutamate, producing rapid-onset euphoria and disinhibition", "Stimulating dopamine release like amphetamines", "Activating opioid receptors in the brainstem", "Blocking serotonin reuptake similar to SSRIs"], correctIndex: 0, rationale: "Volatile solvents rapidly cross the blood-brain barrier and enhance GABA transmission while inhibiting NMDA receptors, similar to alcohol. They also affect multiple ion channels. Sudden sniffing death from cardiac arrhythmia is a major risk.", difficulty: 3, category: "Pharmacology of Substances", topic: "Inhalant Pharmacology" },
  { id: "cac-782", stem: "A client taking disulfiram must be warned about which hidden sources of alcohol?", options: ["Mouthwash, cough syrups, vinegar-based sauces, aftershave, and hand sanitizers", "Only alcoholic beverages such as beer, wine, and spirits", "Caffeinated beverages", "Dairy products"], correctIndex: 0, rationale: "Disulfiram-alcohol reactions can occur with any ethanol source including OTC medications, cooking extracts, topical products, and even some foods prepared with alcohol. Clients need comprehensive education about all potential sources.", difficulty: 2, category: "Pharmacology of Substances", topic: "Alcohol Treatment" },
  { id: "cac-783", stem: "Ketamine's mechanism of action as a dissociative drug involves:", options: ["Non-competitive antagonism of NMDA glutamate receptors", "Agonism at mu-opioid receptors", "Blockade of dopamine transporters", "Enhancement of GABA-A receptor function"], correctIndex: 0, rationale: "Ketamine is a non-competitive NMDA receptor antagonist that produces dissociative anesthesia, analgesia, and psychotomimetic effects. Its rapid antidepressant properties have led to FDA-approved esketamine (Spravato) for treatment-resistant depression.", difficulty: 3, category: "Pharmacology of Substances", topic: "Hallucinogen Mechanisms" },
  { id: "cac-784", stem: "Protracted/post-acute withdrawal syndrome (PAWS) from alcohol may include:", options: ["Anxiety, sleep disturbances, cognitive impairment, and emotional volatility lasting weeks to months", "Only physical symptoms lasting 3-5 days", "Immediate resolution of all symptoms after acute detoxification", "Symptoms identical to delirium tremens"], correctIndex: 0, rationale: "PAWS reflects persistent neuroadaptation after acute withdrawal resolves. Symptoms include emotional instability, poor concentration, sleep disturbance, and stress sensitivity. Understanding PAWS helps clients interpret early recovery difficulties without relapsing.", difficulty: 2, category: "Pharmacology of Substances", topic: "Alcohol Withdrawal" },
  { id: "cac-785", stem: "Carfentanil, found in some illicit drug supplies, is approximately how much more potent than morphine?", options: ["10,000 times more potent", "2 times more potent", "50 times more potent", "500 times more potent"], correctIndex: 0, rationale: "Carfentanil is a synthetic opioid designed for large-animal sedation with approximately 10,000x the potency of morphine and 100x that of fentanyl. Even microgram quantities can be lethal, and standard naloxone doses may be insufficient for reversal.", difficulty: 2, category: "Pharmacology of Substances", topic: "Opioid Mechanisms" },
  { id: "cac-786", stem: "Wernicke's encephalopathy is a medical emergency characterized by the classic triad of:", options: ["Confusion, ataxia, and ophthalmoplegia (eye movement abnormalities)", "Seizures, tachycardia, and diaphoresis", "Hallucinations, tremor, and fever", "Nystagmus, nausea, and peripheral neuropathy only"], correctIndex: 0, rationale: "Wernicke's encephalopathy results from acute thiamine deficiency and presents with the classic triad of encephalopathy (confusion), oculomotor dysfunction (nystagmus, ophthalmoplegia), and cerebellar dysfunction (ataxia). Urgent IV thiamine is required to prevent Korsakoff syndrome.", difficulty: 2, category: "Pharmacology of Substances", topic: "Alcohol Effects" },
  { id: "cac-787", stem: "Which statement about nicotine pharmacology is most accurate?", options: ["Nicotine activates nicotinic acetylcholine receptors, stimulating dopamine release in the nucleus accumbens within 10 seconds of inhalation", "Nicotine primarily affects the endocannabinoid system", "Nicotine has a half-life of 24 hours", "Nicotine produces effects only through peripheral nervous system activation"], correctIndex: 0, rationale: "Inhaled nicotine reaches the brain in ~10 seconds, activating nicotinic acetylcholine receptors (nAChRs) on VTA dopamine neurons. Its short half-life (~2 hours) drives frequent dosing. Upregulation of nAChRs underlies tolerance and withdrawal.", difficulty: 2, category: "Pharmacology of Substances", topic: "Nicotine Pharmacology" },
  { id: "cac-788", stem: "A client on buprenorphine/naloxone (Suboxone) who injects the medication intravenously will experience:", options: ["Precipitated withdrawal due to the naloxone component becoming bioavailable when injected", "Enhanced euphoria from the buprenorphine", "No difference from sublingual administration", "Immediate respiratory arrest"], correctIndex: 0, rationale: "Naloxone has poor sublingual bioavailability (<10%) but high parenteral bioavailability. When Suboxone is injected, naloxone becomes active and can precipitate withdrawal, deterring IV misuse. This is the rationale for the combination product.", difficulty: 3, category: "Pharmacology of Substances", topic: "Opioid Mechanisms" },
  { id: "cac-789", stem: "Serotonin syndrome can occur when MDMA is combined with:", options: ["SSRIs or MAOIs, producing dangerously elevated serotonin levels", "Acetaminophen", "Nicotine replacement therapy", "Caffeine only"], correctIndex: 0, rationale: "MDMA causes massive serotonin release. Combining it with SSRIs (blocking reuptake) or MAOIs (preventing breakdown) can produce life-threatening serotonin syndrome: hyperthermia, rigidity, clonus, agitation, and potential organ failure.", difficulty: 4, category: "Pharmacology of Substances", topic: "Drug Interactions" },
  { id: "cac-790", stem: "Barbiturate withdrawal is considered more dangerous than opioid withdrawal because:", options: ["Barbiturate withdrawal can cause seizures, status epilepticus, and cardiovascular collapse, which can be fatal", "Opioid withdrawal produces more subjective discomfort", "Barbiturate withdrawal only causes mild anxiety", "Barbiturates have no physical dependence potential"], correctIndex: 0, rationale: "Barbiturate and sedative-hypnotic withdrawal, like alcohol withdrawal, involves GABAergic rebound causing potentially fatal seizures, delirium, and autonomic instability. Opioid withdrawal, while extremely uncomfortable, is rarely life-threatening in otherwise healthy adults.", difficulty: 2, category: "Pharmacology of Substances", topic: "Sedative Withdrawal" },
  { id: "cac-791", stem: "Naloxone may need to be administered in repeated doses during fentanyl overdose because:", options: ["Fentanyl's high receptor binding affinity and lipophilicity can outlast naloxone's shorter duration of action", "Naloxone is ineffective against synthetic opioids", "One dose of naloxone permanently reverses all opioid effects", "Fentanyl does not bind to opioid receptors"], correctIndex: 0, rationale: "Naloxone's duration of action (30-90 minutes) may be shorter than fentanyl's effects, especially with large exposures or depot fat release. Patients can re-sedation ('renarcotize') after initial naloxone wears off, requiring repeated dosing or infusion.", difficulty: 3, category: "Pharmacology of Substances", topic: "Opioid Mechanisms" },
  { id: "cac-792", stem: "Alpha-pyrrolidinopentiophenone (alpha-PVP, 'flakka') belongs to which drug class?", options: ["Synthetic cathinones (stimulants) related to bath salts", "Synthetic cannabinoids", "Novel benzodiazepines", "Designer opioids"], correctIndex: 0, rationale: "Alpha-PVP is a potent synthetic cathinone that inhibits dopamine and norepinephrine reuptake. It produces severe agitation, paranoia, hyperthermia, excited delirium, and superhuman-strength behavior. Effects are similar to but more intense than methamphetamine.", difficulty: 4, category: "Pharmacology of Substances", topic: "Emerging Substances" },
  { id: "cac-793", stem: "Chronic alcohol use depletes which neurotransmitter, contributing to alcohol-related depression?", options: ["Serotonin", "Acetylcholine", "Histamine", "Substance P"], correctIndex: 0, rationale: "Chronic alcohol use disrupts serotonin synthesis, release, and receptor function. This depletion contributes to depression, anxiety, and impulsivity seen in alcohol use disorder. Serotonin dysfunction also affects impulse control, increasing relapse risk.", difficulty: 2, category: "Pharmacology of Substances", topic: "Alcohol Effects" },
  { id: "cac-794", stem: "Extended-release naltrexone (Vivitrol) is administered as a monthly intramuscular injection. Its primary advantage over oral naltrexone is:", options: ["Improved adherence by eliminating the need for daily dosing decisions", "Greater efficacy at opioid receptors", "Fewer side effects than oral form", "It also treats benzodiazepine use disorder"], correctIndex: 0, rationale: "The main barrier to oral naltrexone effectiveness is poor adherence — patients simply stop taking it. Monthly IM injection (Vivitrol) provides sustained receptor blockade for ~30 days, removing the daily compliance decision.", difficulty: 2, category: "Pharmacology of Substances", topic: "Opioid Treatment" },
  { id: "cac-795", stem: "DMT (dimethyltryptamine), when used in ayahuasca, requires an MAO inhibitor because:", options: ["DMT is rapidly metabolized by monoamine oxidase in the gut and liver, making it orally inactive without MAO inhibition", "MAOIs enhance the visual effects of DMT", "DMT is only active when combined with serotonin", "MAOIs prevent nausea from DMT"], correctIndex: 0, rationale: "DMT is a potent 5-HT2A agonist but is rapidly broken down by MAO-A when taken orally. Ayahuasca contains harmala alkaloids (MAOIs) that inhibit gut/liver MAO, allowing DMT to reach the brain. This combination also creates serotonin syndrome risk.", difficulty: 5, category: "Pharmacology of Substances", topic: "Hallucinogen Mechanisms" },
  { id: "cac-796", stem: "Alcohol-related thiamine deficiency can be prevented in clinical settings by:", options: ["Administering IV thiamine before glucose-containing fluids in at-risk patients", "Providing oral multivitamins after discharge only", "Ensuring adequate caloric intake without supplementation", "Administering thiamine only after neurological symptoms appear"], correctIndex: 0, rationale: "Thiamine should be given before or with glucose to prevent Wernicke's encephalopathy. Glucose metabolism consumes thiamine, and administering glucose to thiamine-depleted patients can precipitate acute Wernicke's encephalopathy.", difficulty: 3, category: "Pharmacology of Substances", topic: "Alcohol Effects" },
  { id: "cac-797", stem: "Tolerance to opioids develops at different rates for different effects. Tolerance develops LEAST to:", options: ["Miosis (pupil constriction) and constipation", "Euphoria", "Respiratory depression", "Analgesia"], correctIndex: 0, rationale: "Tolerance to opioid-induced euphoria and analgesia develops relatively quickly, driving dose escalation. Tolerance to respiratory depression develops more slowly (increasing overdose risk). Minimal tolerance develops to miosis and constipation, which persist at stable doses.", difficulty: 4, category: "Pharmacology of Substances", topic: "Opioid Effects" },
  { id: "cac-798", stem: "Xylazine ('tranq'), increasingly found in the illicit fentanyl supply, complicates overdose management because:", options: ["It is an alpha-2 adrenergic agonist not reversed by naloxone, causing tissue necrosis and prolonged sedation", "It is a more potent opioid than fentanyl", "Naloxone reverses xylazine effects completely", "It only affects respiratory function"], correctIndex: 0, rationale: "Xylazine is a veterinary sedative (alpha-2 agonist) with no opioid receptor activity. Naloxone does not reverse its effects. It causes severe skin ulceration/necrosis at injection sites and prolongs sedation beyond opioid effects. It represents a growing public health crisis.", difficulty: 4, category: "Pharmacology of Substances", topic: "Emerging Substances" },
  { id: "cac-799", stem: "The 'cheese reaction' is a dangerous drug interaction associated with:", options: ["MAO inhibitors combined with tyramine-rich foods or sympathomimetic drugs, causing hypertensive crisis", "SSRIs combined with cheese-flavored foods", "Opioids combined with dairy products", "Benzodiazepines combined with fermented foods"], correctIndex: 0, rationale: "MAOIs prevent tyramine breakdown. Tyramine in aged cheeses, cured meats, and fermented foods causes massive norepinephrine release, producing hypertensive crisis with potential stroke. This interaction is relevant when MAOIs are combined with substances like amphetamines.", difficulty: 4, category: "Pharmacology of Substances", topic: "Drug Interactions" },
  { id: "cac-800", stem: "What is the primary pharmacological difference between Schedule II and Schedule III opioids?", options: ["Schedule II opioids (morphine, oxycodone) have higher abuse potential and no refills, while Schedule III (combination products with <90mg codeine) have lower potential and allow refills", "There is no meaningful pharmacological difference", "Schedule III drugs are more potent than Schedule II", "Schedule II opioids are only available as injections"], correctIndex: 0, rationale: "DEA scheduling reflects abuse potential. Schedule II includes high-potency full agonists with strict prescribing rules (no refills, limited quantities). Schedule III includes lower-potency formulations and buprenorphine products with somewhat less restrictive prescribing.", difficulty: 3, category: "Pharmacology of Substances", topic: "Opioid Classification" },
  { id: "cac-801", stem: "Cocaine's short half-life of approximately 1 hour leads to which pattern of use?", options: ["Binge-crash cycles with repeated dosing every 15-30 minutes to maintain the high", "Single daily dosing like methadone maintenance", "Weekly use patterns", "Stable blood levels without need for redosing"], correctIndex: 0, rationale: "Cocaine's rapid onset (seconds if smoked/injected) and short duration drive compulsive redosing in binges lasting hours to days. This binge pattern depletes dopamine stores, leading to the 'crash' with profound dysphoria and fatigue.", difficulty: 1, category: "Pharmacology of Substances", topic: "Stimulant Effects" },
  { id: "cac-802", stem: "Absinthe's historically attributed hallucinogenic properties were believed to be caused by:", options: ["Thujone, a compound found in wormwood (Artemisia absinthium)", "THC contamination from hemp", "High alcohol content alone", "Lead acetate used as a sweetener"], correctIndex: 0, rationale: "Thujone in wormwood was long thought to produce hallucinogenic effects and 'absinthism.' Modern research suggests thujone levels in historical absinthe were too low for psychoactive effects, and symptoms were likely due to high alcohol content (45-74% ABV) and chronic alcoholism.", difficulty: 5, category: "Pharmacology of Substances", topic: "Alcohol Effects" },
  { id: "cac-803", stem: "Benzodiazepine withdrawal timeline differs from alcohol withdrawal in that:", options: ["Benzodiazepine withdrawal can be more protracted, lasting weeks to months especially with long-acting agents", "Benzodiazepine withdrawal is always shorter than alcohol withdrawal", "Benzodiazepine withdrawal never produces seizures", "Both withdrawal syndromes are identical in timeline"], correctIndex: 0, rationale: "Long-acting benzodiazepine (diazepam, clonazepam) withdrawal may not peak for 1-2 weeks and can produce protracted symptoms for months. Short-acting agents (alprazolam, lorazepam) have earlier onset. Both can produce life-threatening seizures.", difficulty: 3, category: "Pharmacology of Substances", topic: "Sedative Withdrawal" },
  { id: "cac-804", stem: "N-acetylcysteine (NAC) is being investigated as a treatment for substance use disorders because:", options: ["It modulates glutamate homeostasis by restoring the cystine-glutamate exchanger, reducing drug-seeking behavior", "It is a direct dopamine agonist", "It blocks opioid receptors like naltrexone", "It enhances GABA transmission like benzodiazepines"], correctIndex: 0, rationale: "NAC is a cysteine prodrug that restores function of the glial cystine-glutamate exchanger (system Xc-), normalizing extracellular glutamate levels in the nucleus accumbens. Preliminary evidence supports its use for cannabis, cocaine, and nicotine use disorders.", difficulty: 5, category: "Pharmacology of Substances", topic: "Emerging Treatments" },
  { id: "cac-805", stem: "Which statement about hallucinogen persisting perception disorder (HPPD) is correct?", options: ["It involves persistent visual disturbances (trails, halos, geometric patterns) after hallucinogen use has ceased, sometimes lasting years", "It only occurs during active intoxication", "It is caused exclusively by cannabis use", "It resolves completely within 24 hours of drug cessation"], correctIndex: 0, rationale: "HPPD (DSM-5) involves persistent re-experiencing of perceptual disturbances from prior hallucinogen use (most commonly LSD). Symptoms can be chronic and distressing. The mechanism may involve persistent changes in 5-HT2A receptor signaling or visual cortex processing.", difficulty: 4, category: "Pharmacology of Substances", topic: "Hallucinogen Effects" },
  { id: "cac-806", stem: "Alcohol potentiates the CNS depressant effects of opioids through:", options: ["Additive effects on different inhibitory pathways — alcohol enhances GABA while opioids depress the brainstem respiratory center", "Competition for the same receptor binding sites", "Acceleration of opioid metabolism", "Stimulation of antagonistic pathways"], correctIndex: 0, rationale: "Alcohol and opioids produce CNS depression through different mechanisms that are additive/synergistic. Combined respiratory depression is a leading cause of polysubstance overdose death. Even moderate alcohol consumption with prescribed opioids significantly increases risk.", difficulty: 2, category: "Pharmacology of Substances", topic: "Drug Interactions" },
  { id: "cac-807", stem: "Varenicline (Chantix) aids smoking cessation by:", options: ["Acting as a partial agonist at alpha-4-beta-2 nicotinic receptors, reducing craving and blocking nicotine's reinforcing effects", "Replacing nicotine with a safer stimulant", "Causing an aversive reaction when nicotine is consumed", "Blocking dopamine receptors to eliminate pleasure from smoking"], correctIndex: 0, rationale: "Varenicline's partial agonism provides modest dopamine release (reducing craving/withdrawal) while competitively blocking nicotine from fully activating the receptor (reducing smoking satisfaction). It has the highest single-agent quit rates.", difficulty: 3, category: "Pharmacology of Substances", topic: "Nicotine Pharmacology" },
  { id: "cac-808", stem: "A client reports using 'lean' or 'purple drank.' This substance typically contains:", options: ["Codeine/promethazine cough syrup mixed with soda and candy", "LSD dissolved in grape juice", "Methamphetamine mixed with antihistamines", "Cannabis extract in purple-colored alcohol"], correctIndex: 0, rationale: "Lean/purple drank is a codeine-promethazine cough syrup combination mixed with soda (often Sprite) and hard candy. It provides opioid effects (codeine) enhanced by antihistamine sedation (promethazine). Chronic use leads to opioid dependence and respiratory depression risk.", difficulty: 1, category: "Pharmacology of Substances", topic: "Opioid Effects" },
  { id: "cac-809", stem: "Dextromethorphan (DXM) abuse at high doses produces dissociative effects because:", options: ["At supratherapeutic doses, DXM and its metabolite dextrorphan act as NMDA receptor antagonists similar to PCP and ketamine", "DXM activates opioid receptors at all doses", "DXM enhances GABA activity like alcohol", "DXM blocks serotonin reuptake exclusively"], correctIndex: 0, rationale: "DXM at therapeutic doses is an antitussive, but at high doses (300-1500mg) it becomes a dissociative hallucinogen through NMDA antagonism. Users describe 'plateaus' of escalating effects. Serotonin syndrome risk exists with concurrent SSRI use.", difficulty: 3, category: "Pharmacology of Substances", topic: "Hallucinogen Mechanisms" },
  { id: "cac-810", stem: "The pharmacological basis of cross-tolerance between alcohol and benzodiazepines is:", options: ["Both act on the GABA-A receptor complex, and neuroadaptations from chronic use of one transfer to the other", "Both are metabolized by the same liver enzyme exclusively", "Both activate dopamine receptors identically", "There is no cross-tolerance between these substances"], correctIndex: 0, rationale: "Alcohol and benzodiazepines both enhance GABA-A receptor function (at different binding sites). Chronic exposure to either causes compensatory downregulation of GABA-A receptors and upregulation of glutamate, producing cross-tolerance and cross-dependence.", difficulty: 3, category: "Pharmacology of Substances", topic: "Drug Interactions" },
  { id: "cac-811", stem: "Chronic methamphetamine use causes neurotoxicity primarily by:", options: ["Damaging dopaminergic and serotonergic nerve terminals through oxidative stress and excitotoxicity", "Increasing brain volume and neurogenesis", "Enhancing myelination of cortical neurons", "Improving neurotransmitter receptor sensitivity"], correctIndex: 0, rationale: "Methamphetamine causes oxidative stress through excessive dopamine/norepinephrine release, mitochondrial dysfunction, and hyperthermia. This damages monoaminergic neurons, particularly in the striatum, producing lasting cognitive and motor deficits. Partial recovery is possible with prolonged abstinence.", difficulty: 4, category: "Pharmacology of Substances", topic: "Stimulant Effects" },
  { id: "cac-812", stem: "Clonidine is used as an adjunctive medication in opioid withdrawal management because:", options: ["It reduces adrenergic hyperactivity (anxiety, tachycardia, sweating, restlessness) by stimulating alpha-2 adrenergic autoreceptors", "It replaces opioids at mu receptors", "It blocks opioid receptors to speed detoxification", "It enhances GABA activity to prevent seizures"], correctIndex: 0, rationale: "Opioid withdrawal activates the locus coeruleus, producing noradrenergic hyperactivity. Clonidine, an alpha-2 agonist, reduces norepinephrine release, alleviating autonomic symptoms (tachycardia, hypertension, sweating) but does not address craving or myalgia.", difficulty: 3, category: "Pharmacology of Substances", topic: "Opioid Withdrawal" },
  { id: "cac-813", stem: "What is the primary concern with combining alcohol and acetaminophen?", options: ["Alcohol induces CYP2E1, increasing formation of NAPQI (a hepatotoxic acetaminophen metabolite) beyond glutathione's capacity to neutralize it", "Acetaminophen blocks alcohol absorption", "The combination produces hallucinations", "Alcohol prevents acetaminophen from being absorbed"], correctIndex: 0, rationale: "Chronic alcohol use induces CYP2E1, which converts more acetaminophen to the toxic metabolite NAPQI. Simultaneously, alcohol depletes hepatic glutathione needed to conjugate NAPQI. This dual mechanism dramatically increases hepatotoxicity risk even at therapeutic acetaminophen doses.", difficulty: 4, category: "Pharmacology of Substances", topic: "Drug Interactions" },
  { id: "cac-814", stem: "Which substance has the highest lethality risk during unsupervised withdrawal?", options: ["Alcohol", "Heroin", "Cannabis", "Cocaine"], correctIndex: 0, rationale: "Alcohol (and other sedative-hypnotic) withdrawal can produce fatal seizures, status epilepticus, delirium tremens, and cardiovascular collapse. Opioid withdrawal, while extremely uncomfortable, is rarely fatal in otherwise healthy adults. Cannabis and stimulant withdrawal are not life-threatening.", difficulty: 1, category: "Pharmacology of Substances", topic: "Alcohol Withdrawal" },
  { id: "cac-815", stem: "Heroin is more lipophilic than morphine, which clinically means:", options: ["It crosses the blood-brain barrier faster, producing more rapid onset of euphoria and greater addiction potential", "It has a longer duration of action", "It is less potent than morphine", "It cannot be injected intravenously"], correctIndex: 0, rationale: "Heroin (diacetylmorphine) is more lipid-soluble than morphine due to its acetyl groups, allowing faster BBB penetration. This rapid onset ('rush') contributes to its higher abuse potential compared to morphine, even though heroin is a prodrug converted to morphine.", difficulty: 2, category: "Pharmacology of Substances", topic: "Opioid Mechanisms" },
  { id: "cac-816", stem: "Cannabis hyperemesis syndrome is characterized by:", options: ["Cyclic episodes of severe nausea and vomiting in chronic cannabis users, often relieved by hot showers", "Increased appetite and weight gain", "Respiratory depression", "Seizures during cannabis withdrawal"], correctIndex: 0, rationale: "Cannabis hyperemesis syndrome (CHS) occurs in chronic heavy users and involves cyclic vomiting, abdominal pain, and compulsive hot bathing for relief. Paradoxically, cannabis is antiemetic at lower doses but CHS develops with chronic use, possibly from CB1 receptor dysregulation in the gut.", difficulty: 2, category: "Pharmacology of Substances", topic: "Cannabis Effects" },
  { id: "cac-817", stem: "A client prescribed lithium who uses alcohol heavily is at increased risk for:", options: ["Lithium toxicity due to alcohol-induced dehydration and electrolyte imbalances affecting lithium clearance", "Enhanced lithium efficacy", "Decreased lithium absorption", "Allergic reaction to lithium"], correctIndex: 0, rationale: "Alcohol causes dehydration, vomiting, and diarrhea, reducing renal lithium clearance and increasing serum lithium levels toward toxicity. Alcohol-induced fluctuations in fluid status make lithium management unpredictable in active drinkers.", difficulty: 4, category: "Pharmacology of Substances", topic: "Drug Interactions" },
  { id: "cac-818", stem: "The primary active metabolite of heroin that produces its euphoric effects is:", options: ["6-monoacetylmorphine (6-MAM) and then morphine", "Codeine", "Naloxone", "Fentanyl"], correctIndex: 0, rationale: "Heroin is rapidly deacetylated to 6-MAM (which crosses the BBB efficiently and is detectable as a heroin-specific metabolite) and then to morphine, which is the primary active compound at mu-opioid receptors producing analgesia and euphoria.", difficulty: 4, category: "Pharmacology of Substances", topic: "Opioid Mechanisms" },
  { id: "cac-819", stem: "Phenobarbital is sometimes preferred over benzodiazepines for alcohol withdrawal management because:", options: ["It has a very long half-life providing self-tapering effects, may be effective in benzodiazepine-resistant withdrawal, and has lower abuse potential", "It works faster than benzodiazepines", "It has no sedative properties", "It is available only as an IV formulation"], correctIndex: 0, rationale: "Phenobarbital's long half-life (80-120 hours) provides smooth, self-tapering coverage. It acts at a different GABA-A receptor site than benzodiazepines and may rescue benzodiazepine-resistant withdrawal. Loading-dose protocols reduce ICU admissions.", difficulty: 5, category: "Pharmacology of Substances", topic: "Alcohol Withdrawal" },
  { id: "cac-820", stem: "Salvia divinorum produces its hallucinogenic effects through a unique mechanism involving:", options: ["Selective kappa-opioid receptor agonism, distinct from classic serotonergic hallucinogens", "5-HT2A serotonin receptor agonism like LSD", "NMDA receptor antagonism like ketamine", "CB1 cannabinoid receptor activation like THC"], correctIndex: 0, rationale: "Salvinorin A is a potent and selective kappa-opioid receptor (KOR) agonist — the only known naturally occurring KOR agonist hallucinogen. Effects include intense but brief (5-20 minutes when smoked) dissociation and dysphoria, distinct from serotonergic hallucinogen experiences.", difficulty: 5, category: "Pharmacology of Substances", topic: "Hallucinogen Mechanisms" },
  { id: "cac-821", stem: "Which electrolyte abnormality is most commonly associated with chronic alcohol use and can cause seizures?", options: ["Hypomagnesemia", "Hyperkalemia", "Hypercalcemia", "Hypernatremia"], correctIndex: 0, rationale: "Chronic alcohol use causes renal magnesium wasting, poor dietary intake, and GI losses. Hypomagnesemia lowers seizure threshold, contributes to cardiac arrhythmias, and exacerbates other electrolyte abnormalities (hypokalemia, hypocalcemia). Magnesium replacement is standard in alcohol withdrawal.", difficulty: 3, category: "Pharmacology of Substances", topic: "Alcohol Effects" },
  { id: "cac-822", stem: "Amphetamine produces its stimulant effects differently from cocaine because amphetamine:", options: ["Causes active release of dopamine from presynaptic vesicles in addition to blocking reuptake", "Only blocks dopamine reuptake without affecting release", "Acts exclusively on serotonin systems", "Has no effect on norepinephrine"], correctIndex: 0, rationale: "Unlike cocaine (pure reuptake inhibitor), amphetamine enters presynaptic neurons via DAT, displaces dopamine from vesicles via VMAT2, and reverses DAT function to pump dopamine into the synapse. This dual mechanism produces greater and more sustained dopamine elevation.", difficulty: 3, category: "Pharmacology of Substances", topic: "Stimulant Mechanisms" },
  { id: "cac-823", stem: "A client using both alcohol and cocaine may form which unique metabolite?", options: ["Cocaethylene, which has a longer half-life and greater cardiotoxicity than either substance alone", "Norcocaine, which is pharmacologically inactive", "Benzoylecgonine, which enhances alcohol effects", "Ethanol glucuronide, which blocks cocaine effects"], correctIndex: 0, rationale: "When cocaine and alcohol are co-ingested, hepatic transesterification produces cocaethylene. This active metabolite has a longer half-life than cocaine and produces greater euphoria but also greater cardiotoxicity, increasing sudden death risk 18-25 fold.", difficulty: 4, category: "Pharmacology of Substances", topic: "Drug Interactions" },
  { id: "cac-824", stem: "Nitrous oxide abuse can lead to which serious neurological complication?", options: ["Vitamin B12 (cobalamin) inactivation causing subacute combined degeneration of the spinal cord", "Thiamine deficiency causing Wernicke's encephalopathy", "Folate deficiency causing megaloblastic anemia only", "Iron deficiency causing peripheral neuropathy"], correctIndex: 0, rationale: "Nitrous oxide irreversibly oxidizes the cobalt in vitamin B12, inactivating methionine synthase. This disrupts myelin synthesis, causing subacute combined degeneration with posterior column and lateral corticospinal tract dysfunction (numbness, weakness, ataxia).", difficulty: 5, category: "Pharmacology of Substances", topic: "Inhalant Pharmacology" },
  { id: "cac-825", stem: "What is the recommended minimum observation period after naloxone administration for opioid overdose reversal?", options: ["At least 2-4 hours, as naloxone may wear off before the opioid, causing re-sedation", "15 minutes is sufficient", "The patient can be discharged immediately after regaining consciousness", "24 hours of ICU monitoring is always required"], correctIndex: 0, rationale: "Naloxone has a shorter duration of action (30-90 minutes) than most opioids. After initial reversal, patients may re-sedate as naloxone wears off. Minimum 2-4 hour observation is recommended, longer for long-acting opioids (methadone) or sustained-release formulations.", difficulty: 2, category: "Pharmacology of Substances", topic: "Opioid Treatment" },
  { id: "cac-826", stem: "Gabapentin is FDA-approved for alcohol use disorder in which form?", options: ["Gabapentin is not FDA-approved for AUD but is used off-label; however, gabapentin enacarbil is also not approved for AUD", "Extended-release gabapentin (Horizant) is FDA-approved for AUD", "Gabapentin is FDA-approved specifically for alcohol withdrawal seizures", "All gabapentin formulations are FDA-approved for AUD"], correctIndex: 0, rationale: "While gabapentin shows promise for AUD (reducing heavy drinking, craving, and insomnia) in clinical trials, it is not FDA-approved for this indication. FDA-approved AUD medications are naltrexone, acamprosate, and disulfiram. Gabapentin's abuse potential limits its enthusiasm.", difficulty: 3, category: "Pharmacology of Substances", topic: "Alcohol Treatment" },
  { id: "cac-827", stem: "A client reports using 'poppers.' The pharmacology of this substance involves:", options: ["Alkyl nitrites that cause rapid vasodilation, smooth muscle relaxation, and brief euphoria through nitric oxide release", "Synthetic cathinones that release dopamine", "Benzodiazepine analogs that enhance GABA", "Dissociative anesthetics blocking NMDA receptors"], correctIndex: 0, rationale: "Poppers (amyl, butyl, or isobutyl nitrite) are volatile liquids inhaled for rapid vasodilation and muscle relaxation. They cause headache, dizziness, and brief euphoria. Risks include methemoglobinemia, severe hypotension (especially with PDE5 inhibitors like sildenafil), and maculopathy.", difficulty: 3, category: "Pharmacology of Substances", topic: "Inhalant Pharmacology" },
  { id: "cac-828", stem: "Opioid-induced hyperalgesia differs from tolerance in that:", options: ["Hyperalgesia involves increased pain sensitivity caused by opioids themselves, while tolerance requires higher doses for the same effect", "They are identical phenomena", "Hyperalgesia only occurs with synthetic opioids", "Tolerance involves increased pain sensitivity"], correctIndex: 0, rationale: "Opioid-induced hyperalgesia (OIH) is a paradoxical increase in pain sensitivity caused by opioid use, involving NMDA receptor activation and central sensitization. Unlike tolerance (needing more drug for same effect), OIH means the opioid itself is generating pain, and dose increases worsen it.", difficulty: 4, category: "Pharmacology of Substances", topic: "Opioid Effects" },
  { id: "cac-829", stem: "What is the mechanism by which alcohol causes fetal alcohol spectrum disorders?", options: ["Alcohol freely crosses the placenta and disrupts fetal cell migration, differentiation, and apoptosis particularly in the developing brain", "Alcohol cannot cross the placenta but causes maternal nutritional deficiency", "FASD is caused solely by genetic factors unrelated to alcohol exposure", "Alcohol only affects the fetus during the third trimester"], correctIndex: 0, rationale: "Ethanol and acetaldehyde cross the placenta freely. They disrupt neural crest cell migration, alter gene expression through epigenetic mechanisms, increase oxidative stress, and impair neuronal proliferation and survival. The fetal liver has minimal alcohol dehydrogenase, prolonging exposure.", difficulty: 3, category: "Pharmacology of Substances", topic: "Alcohol Effects" },
  { id: "cac-830", stem: "Methadone's long half-life (24-36 hours) is therapeutically advantageous because:", options: ["It provides stable blood levels preventing withdrawal and craving throughout the day with once-daily dosing", "It produces stronger euphoria than short-acting opioids", "It allows for every-other-day dosing from the start", "It eliminates the need for medical monitoring"], correctIndex: 0, rationale: "Methadone's long half-life maintains steady-state plasma levels, preventing the peaks and troughs that drive compulsive dosing with short-acting opioids. This stability reduces craving and withdrawal while developing cross-tolerance that blocks euphoria from illicit opioid use.", difficulty: 1, category: "Pharmacology of Substances", topic: "Opioid Treatment" },
  { id: "cac-831", stem: "Which hallucinogen is classified as an empathogen/entactogen rather than a classic hallucinogen?", options: ["MDMA (3,4-methylenedioxymethamphetamine)", "LSD (lysergic acid diethylamide)", "Psilocybin", "Mescaline"], correctIndex: 0, rationale: "MDMA is classified as an empathogen/entactogen because its primary effects are emotional warmth, empathy, and interpersonal closeness rather than perceptual hallucinations. Its mechanism (massive serotonin release) differs from classic hallucinogens (5-HT2A agonism).", difficulty: 2, category: "Pharmacology of Substances", topic: "Hallucinogen Effects" },
  { id: "cac-832", stem: "Chronic benzodiazepine use leads to downregulation of GABA-A receptors. This neuroadaptation explains:", options: ["The development of tolerance (needing higher doses) and the emergence of withdrawal symptoms upon discontinuation", "Why benzodiazepines become more effective over time", "Why patients can safely stop benzodiazepines abruptly", "Why cross-tolerance with opioids develops"], correctIndex: 0, rationale: "Chronic GABA-A stimulation causes receptor internalization and subunit composition changes (downregulation). This reduces benzodiazepine efficacy (tolerance) and creates a deficit state upon discontinuation, producing anxiety, insomnia, and potentially seizures (withdrawal).", difficulty: 3, category: "Pharmacology of Substances", topic: "Sedative Mechanisms" },
  { id: "cac-833", stem: "What is the pharmacological basis for using lofexidine (Lucemyra) in opioid withdrawal?", options: ["It is an alpha-2 adrenergic agonist that reduces noradrenergic hyperactivity without significant hypotension compared to clonidine", "It replaces opioids at mu receptors", "It blocks NMDA receptors to reduce withdrawal severity", "It enhances serotonin to improve mood during withdrawal"], correctIndex: 0, rationale: "Lofexidine is the first FDA-approved non-opioid medication for opioid withdrawal symptoms. Like clonidine, it reduces locus coeruleus noradrenergic overactivity, but with less hypotension and a shorter half-life allowing better dose titration.", difficulty: 4, category: "Pharmacology of Substances", topic: "Opioid Withdrawal" },
  { id: "cac-834", stem: "Stimulant use can unmask or trigger latent psychotic symptoms because:", options: ["Excessive dopamine release in the mesolimbic and mesocortical pathways mimics the dopaminergic dysregulation seen in schizophrenia", "Stimulants deplete serotonin, causing hallucinations", "Stimulants block GABA, causing disinhibition of psychotic thought", "Psychosis only occurs during stimulant withdrawal, not intoxication"], correctIndex: 0, rationale: "Stimulant-induced psychosis is caused by excessive dopamine activity, particularly in mesolimbic pathways — the same mechanism proposed in the dopamine hypothesis of schizophrenia. Chronic use sensitizes dopamine circuits (reverse tolerance), increasing psychosis risk with repeated exposure.", difficulty: 3, category: "Pharmacology of Substances", topic: "Stimulant Effects" },
  { id: "cac-835", stem: "Why is flumazenil (Romazicon) used cautiously in benzodiazepine-dependent patients?", options: ["It can precipitate severe withdrawal including seizures by rapidly reversing benzodiazepine effects at GABA-A receptors", "It enhances benzodiazepine effects causing deeper sedation", "It has no clinical effects in dependent patients", "It converts benzodiazepines to active metabolites"], correctIndex: 0, rationale: "Flumazenil is a competitive benzodiazepine antagonist. In dependent patients, rapid GABA-A receptor unblocking causes acute withdrawal with seizures, arrhythmias, and potentially death. It is generally reserved for iatrogenic oversedation in non-dependent patients.", difficulty: 3, category: "Pharmacology of Substances", topic: "Sedative Mechanisms" },
  { id: "cac-836", stem: "Alcohol's effect on the hypothalamic-pituitary-adrenal (HPA) axis during chronic use includes:", options: ["Chronic HPA axis activation with elevated cortisol, contributing to stress sensitivity and negative reinforcement drinking during withdrawal", "Suppression of cortisol production at all stages", "No effect on the stress response system", "Normalization of cortisol levels"], correctIndex: 0, rationale: "Chronic alcohol dysregulates the HPA axis, elevating cortisol and corticotropin-releasing factor (CRF). During withdrawal, HPA hyperactivity produces anxiety and dysphoria, driving negative reinforcement (drinking to relieve withdrawal distress). This allostatic load model explains compulsive drinking.", difficulty: 4, category: "Pharmacology of Substances", topic: "Alcohol Mechanisms" },
  { id: "cac-837", stem: "Which of the following is a pharmacologically accurate statement about caffeine?", options: ["Caffeine blocks adenosine receptors, preventing drowsiness and increasing dopamine signaling, and can produce mild physical dependence", "Caffeine directly stimulates dopamine release like cocaine", "Caffeine has no withdrawal syndrome", "Caffeine acts primarily on opioid receptors"], correctIndex: 0, rationale: "Caffeine is an adenosine A1 and A2A receptor antagonist. Blocking adenosine's inhibitory effects increases alertness and indirectly enhances dopamine signaling. Regular use produces tolerance and a recognized withdrawal syndrome (headache, fatigue, irritability) beginning 12-24 hours after last dose.", difficulty: 1, category: "Pharmacology of Substances", topic: "Stimulant Mechanisms" },
  { id: "cac-838", stem: "Pregabalin withdrawal after chronic use at high doses can produce:", options: ["Anxiety, insomnia, nausea, sweating, and rarely seizures — similar to but generally milder than benzodiazepine withdrawal", "No withdrawal symptoms of any kind", "Opioid-like withdrawal with diarrhea and muscle cramps", "Stimulant-like crash with hypersomnia"], correctIndex: 0, rationale: "Pregabalin binds voltage-gated calcium channel alpha-2-delta subunits, reducing excitatory neurotransmitter release. Chronic use leads to compensatory upregulation, and abrupt discontinuation can produce a withdrawal syndrome including anxiety, insomnia, and seizures (rare). Gradual taper is recommended.", difficulty: 4, category: "Pharmacology of Substances", topic: "Sedative Withdrawal" },
  { id: "cac-839", stem: "Alcohol's teratogenic effects are most severe on which organ system?", options: ["Central nervous system, with effects on brain structure and function throughout pregnancy", "Cardiovascular system exclusively", "Musculoskeletal system only", "Immune system only"], correctIndex: 0, rationale: "The CNS is the most sensitive organ to alcohol teratogenicity and is vulnerable throughout pregnancy. First trimester exposure causes structural brain abnormalities; second/third trimester exposure causes neuronal migration deficits and white matter damage. Facial dysmorphology requires first trimester exposure.", difficulty: 2, category: "Pharmacology of Substances", topic: "Alcohol Effects" },
  { id: "cac-840", stem: "What is the clinical significance of CYP2D6 polymorphisms in opioid pharmacology?", options: ["They determine codeine's conversion to morphine — poor metabolizers get no analgesic effect while ultra-rapid metabolizers face toxicity/overdose risk", "CYP2D6 has no role in opioid metabolism", "All opioids are metabolized identically regardless of CYP2D6 status", "CYP2D6 polymorphisms only affect stimulant metabolism"], correctIndex: 0, rationale: "CYP2D6 converts codeine to morphine, tramadol to O-desmethyltramadol, and hydrocodone to hydromorphone. Ultra-rapid metabolizers produce excessive active metabolite (causing respiratory depression, particularly dangerous in children). Poor metabolizers receive inadequate analgesia.", difficulty: 5, category: "Pharmacology of Substances", topic: "Opioid Mechanisms" },
  { id: "cac-841", stem: "A client with alcohol use disorder who takes metformin for diabetes is at increased risk for:", options: ["Lactic acidosis, as both alcohol and metformin independently impair lactate metabolism", "Hypoglycemia from metformin only", "Enhanced metformin efficacy", "Vitamin D deficiency"], correctIndex: 0, rationale: "Alcohol inhibits gluconeogenesis and lactate clearance while metformin inhibits mitochondrial complex I and hepatic lactate uptake. Combined use significantly increases lactic acidosis risk, a rare but potentially fatal complication, especially with binge drinking.", difficulty: 5, category: "Pharmacology of Substances", topic: "Drug Interactions" },
  { id: "cac-842", stem: "Delta-8-THC, marketed as 'legal' cannabis, differs from delta-9-THC pharmacologically in that:", options: ["It has lower binding affinity at CB1 receptors producing reportedly milder psychoactive effects, but safety data is limited due to unregulated synthetic conversion processes", "It is completely non-psychoactive", "It is more potent than delta-9-THC", "It acts on opioid receptors rather than cannabinoid receptors"], correctIndex: 0, rationale: "Delta-8-THC is a positional isomer of delta-9-THC with lower CB1 affinity (~50-75% potency). Most commercial delta-8 is synthesized from CBD through acid catalysis, with concerns about residual solvents, byproducts, and lack of quality control. It produces genuine psychoactive effects.", difficulty: 3, category: "Pharmacology of Substances", topic: "Cannabis Pharmacology" },
  { id: "cac-843", stem: "The COWS (Clinical Opiate Withdrawal Scale) is used to:", options: ["Objectively quantify the severity of opioid withdrawal symptoms to guide medication-assisted treatment initiation", "Screen for opioid use disorder", "Measure blood opioid levels", "Assess long-term recovery progress"], correctIndex: 0, rationale: "COWS measures 11 signs/symptoms (pulse rate, sweating, restlessness, pupil size, bone/joint aches, rhinorrhea, GI upset, tremor, yawning, anxiety, piloerection). Scores guide buprenorphine induction timing — a score ≥8-12 typically indicates sufficient withdrawal to begin dosing.", difficulty: 1, category: "Pharmacology of Substances", topic: "Opioid Withdrawal" },
  { id: "cac-844", stem: "Methaqualone (Quaalude), though largely unavailable in the US, exerts its effects through:", options: ["GABA-A receptor positive allosteric modulation similar to barbiturates, producing sedation, anxiolysis, and euphoria", "Opioid receptor agonism", "NMDA receptor antagonism", "Selective serotonin reuptake inhibition"], correctIndex: 0, rationale: "Methaqualone is a sedative-hypnotic that enhances GABA-A activity at a binding site distinct from benzodiazepines and barbiturates. It produces euphoria, disinhibition, and enhanced tactile sensation, contributing to its high abuse potential. Overdose risk includes seizures and cardiac failure.", difficulty: 5, category: "Pharmacology of Substances", topic: "Sedative Mechanisms" },
  { id: "cac-845", stem: "Cannabis potency (THC concentration) has changed significantly over recent decades. This is clinically relevant because:", options: ["Average THC concentration has increased from ~4% in the 1990s to 15-25%+ today, increasing risks of psychosis, dependence, and cannabis hyperemesis syndrome", "THC concentrations have remained constant", "Higher potency reduces health risks", "Only CBD concentrations have changed"], correctIndex: 0, rationale: "Selective cultivation has dramatically increased THC content while decreasing CBD (which may be protective). Higher potency cannabis is associated with greater psychosis risk, faster development of cannabis use disorder, more severe withdrawal, and increased emergency department visits.", difficulty: 2, category: "Pharmacology of Substances", topic: "Cannabis Effects" },
  { id: "cac-846", stem: "Ibogaine, used in some countries for opioid detoxification, carries which major medical risk?", options: ["QTc prolongation and fatal cardiac arrhythmias", "Hepatorenal syndrome", "Status epilepticus", "Malignant hyperthermia"], correctIndex: 0, rationale: "Ibogaine blocks hERG potassium channels, prolonging cardiac repolarization (QTc). Multiple deaths from cardiac arrhythmias have been reported. It also affects multiple receptor systems (opioid, NMDA, serotonin, nicotinic). It remains unscheduled but unapproved in the US.", difficulty: 5, category: "Pharmacology of Substances", topic: "Emerging Treatments" },
  { id: "cac-847", stem: "In the context of opioid pharmacology, a 'speedball' refers to:", options: ["The combination of heroin (or another opioid) with cocaine, producing simultaneous stimulant and depressant effects", "A rapid-acting opioid taken sublingually", "An extended-release opioid formulation", "A high-dose methadone protocol"], correctIndex: 0, rationale: "A speedball combines an opioid (typically heroin) with cocaine for combined stimulant-depressant effects. The combination is particularly dangerous because cocaine's short duration wears off, leaving unopposed opioid respiratory depression. Many high-profile overdose deaths involve this combination.", difficulty: 1, category: "Pharmacology of Substances", topic: "Drug Interactions" },
  { id: "cac-848", stem: "Chronic cannabis use affects the endocannabinoid system by:", options: ["Downregulating and desensitizing CB1 receptors, leading to tolerance, and requiring 2-4 weeks of abstinence for receptor recovery", "Permanently destroying CB1 receptors", "Upregulating CB2 receptors exclusively", "Having no effect on endocannabinoid receptor density"], correctIndex: 0, rationale: "Chronic THC exposure causes CB1 receptor internalization (downregulation) and desensitization. PET imaging studies show receptor recovery beginning within 2 days of abstinence and substantial normalization by 4 weeks, correlating with withdrawal symptom resolution.", difficulty: 3, category: "Pharmacology of Substances", topic: "Cannabis Pharmacology" },
  { id: "cac-849", stem: "Which medication is FDA-approved for both opioid use disorder and alcohol use disorder?", options: ["Naltrexone", "Methadone", "Acamprosate", "Disulfiram"], correctIndex: 0, rationale: "Naltrexone (oral and extended-release injectable) is FDA-approved for both AUD and OUD. For AUD, it reduces heavy drinking through opioid receptor blockade diminishing alcohol's rewarding effects. For OUD, it blocks opioid euphoria. Methadone is approved only for OUD.", difficulty: 1, category: "Pharmacology of Substances", topic: "Opioid Treatment" },
  { id: "cac-850", stem: "The concept of receptor downregulation in addiction pharmacology explains:", options: ["How chronic drug exposure leads to decreased receptor density or sensitivity, requiring more drug (tolerance) and producing withdrawal when drug is removed", "How drugs permanently increase receptor numbers", "Why single doses of drugs produce lifelong effects", "How receptors regenerate after drug exposure within hours"], correctIndex: 0, rationale: "Receptor downregulation (decreased number or sensitivity) is a homeostatic response to chronic agonist exposure. This creates a new set point requiring continued drug presence for normal function (dependence) and producing a deficit state during abstinence (withdrawal). It is a key mechanism underlying tolerance.", difficulty: 2, category: "Pharmacology of Substances", topic: "Neurobiology of Addiction" },
];
